import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const s = {
  page: { padding: 32, maxWidth: 900, margin: '0 auto' },
  greeting: { fontSize: 26, fontWeight: 700, color: '#1a3a5c', marginBottom: 4 },
  sub: { color: '#888', marginBottom: 28 },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 20, marginBottom: 32 },
  statCard: { background: '#fff', borderRadius: 14, padding: '24px 20px', boxShadow: '0 2px 12px rgba(0,0,0,0.07)', textAlign: 'center' },
  statNum: { fontSize: 36, fontWeight: 800, marginBottom: 4 },
  statLabel: { fontSize: 13, color: '#888', fontWeight: 500 },
  actions: { display: 'flex', gap: 16, marginBottom: 32 },
  btn: { padding: '12px 28px', borderRadius: 10, fontWeight: 700, fontSize: 15, cursor: 'pointer', border: 'none', textDecoration: 'none', display: 'inline-block' },
  sectionTitle: { fontSize: 18, fontWeight: 700, color: '#1a3a5c', marginBottom: 16 },
  table: { width: '100%', borderCollapse: 'collapse', background: '#fff', borderRadius: 12, overflow: 'hidden', boxShadow: '0 2px 12px rgba(0,0,0,0.07)' },
  th: { background: '#1a3a5c', color: '#fff', padding: '12px 16px', textAlign: 'left', fontSize: 13 },
  td: { padding: '12px 16px', borderBottom: '1px solid #f0f0f0', fontSize: 14 },
};

const statusColor = { pending: '#f39c12', approved: '#27ae60', rejected: '#e74c3c', expired: '#95a5a6' };

export default function StudentDashboard() {
  const { user } = useAuth();
  const [passes, setPasses] = useState([]);

  useEffect(() => {
    axios.get('/api/pass/my').then(r => setPasses(r.data)).catch(() => {});
  }, []);

  const latest = passes[0];
  const approved = passes.filter(p => p.status === 'approved').length;
  const pending = passes.filter(p => p.status === 'pending').length;

  return (
    <div style={s.page}>
      <div style={s.greeting}>Welcome, {user?.name} 👋</div>
      <div style={s.sub}>USN: {user?.usn} · NIE Mysuru</div>

      <div style={s.grid}>
        <div style={s.statCard}><div style={{ ...s.statNum, color: '#2980b9' }}>{passes.length}</div><div style={s.statLabel}>Total Applications</div></div>
        <div style={s.statCard}><div style={{ ...s.statNum, color: '#27ae60' }}>{approved}</div><div style={s.statLabel}>Approved Passes</div></div>
        <div style={s.statCard}><div style={{ ...s.statNum, color: '#f39c12' }}>{pending}</div><div style={s.statLabel}>Pending</div></div>
      </div>

      {latest?.status === 'approved' && (
        <div style={{ background: '#eafaf1', border: '2px solid #27ae60', borderRadius: 14, padding: '20px 24px', marginBottom: 28 }}>
          <div style={{ fontWeight: 700, color: '#27ae60', fontSize: 16, marginBottom: 8 }}>✅ Active Bus Pass</div>
          <div style={{ fontSize: 14, color: '#333' }}>Pass No: <strong>{latest.passNumber}</strong> &nbsp;|&nbsp; Route: {latest.from} → {latest.to} &nbsp;|&nbsp; Valid till: <strong>{new Date(latest.validTo).toLocaleDateString()}</strong></div>
        </div>
      )}

      <div style={s.actions}>
        <Link to="/apply" style={{ ...s.btn, background: '#1a3a5c', color: '#fff' }}>+ Apply for Pass</Link>
        <Link to="/my-passes" style={{ ...s.btn, background: '#fff', color: '#1a3a5c', border: '2px solid #1a3a5c' }}>View All Passes</Link>
      </div>

      <div style={s.sectionTitle}>Recent Applications</div>
      <table style={s.table}>
        <thead><tr><th style={s.th}>Pass No</th><th style={s.th}>Route</th><th style={s.th}>Type</th><th style={s.th}>Applied</th><th style={s.th}>Status</th></tr></thead>
        <tbody>
          {passes.slice(0, 5).map(p => (
            <tr key={p._id}>
              <td style={s.td}>{p.passNumber || '—'}</td>
              <td style={s.td}>{p.from} → {p.to}</td>
              <td style={s.td}>{p.passType}</td>
              <td style={s.td}>{new Date(p.appliedAt).toLocaleDateString()}</td>
              <td style={s.td}><span style={{ background: statusColor[p.status] + '22', color: statusColor[p.status], padding: '3px 12px', borderRadius: 20, fontSize: 13, fontWeight: 600 }}>{p.status}</span></td>
            </tr>
          ))}
          {passes.length === 0 && <tr><td colSpan={5} style={{ ...s.td, textAlign: 'center', color: '#aaa' }}>No applications yet</td></tr>}
        </tbody>
      </table>
    </div>
  );
}
